import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.List;

public class SolutionTest {

    @Test
    void typicalAddAndRemove() {
        // ADD apple, ADD banana, ADD apple (duplicate), REMOVE banana
        // -> [apple, apple]
        assertEquals(List.of("apple", "apple"),
                new Solution().finalCart(
                        new String[]{"ADD:apple", "ADD:banana", "ADD:apple", "REMOVE:banana"}));
    }

    @Test
    void emptyOps() {
        assertEquals(List.of(),
                new Solution().finalCart(new String[]{}));
    }

    @Test
    void singleAdd() {
        assertEquals(List.of("milk"),
                new Solution().finalCart(new String[]{"ADD:milk"}));
    }

    @Test
    void removeAbsentItemIsNoOp() {
        // REMOVE on an item never added must not throw and must leave cart unchanged
        assertEquals(List.of(),
                new Solution().finalCart(new String[]{"REMOVE:nothing"}));
    }

    @Test
    void orderMatters() {
        // ADD milk, REMOVE milk, ADD milk -> [milk]
        // If the algorithm were order-independent it might return [] (two adds, two removes)
        // The final state depends strictly on chronological order.
        assertEquals(List.of("milk"),
                new Solution().finalCart(
                        new String[]{"ADD:milk", "REMOVE:milk", "ADD:milk"}));
    }

    @Test
    void removeOnlyFirstOccurrenceOfDuplicate() {
        // ADD apple, ADD apple, REMOVE apple -> first apple gone, second remains
        assertEquals(List.of("apple"),
                new Solution().finalCart(
                        new String[]{"ADD:apple", "ADD:apple", "REMOVE:apple"}));
    }

    @Test
    void preserveInsertionOrderAfterRemoves() {
        // ADD a, ADD b, ADD c, REMOVE b -> [a, c] — b removed from middle
        assertEquals(List.of("a", "c"),
                new Solution().finalCart(
                        new String[]{"ADD:a", "ADD:b", "ADD:c", "REMOVE:b"}));
    }
}
